insert into public.cb_sections (id, slug, title, description, sort_order)
values
  ('information', 'information', 'Когда много информации', 'Когда много информации', 2),
  ('meaning', 'meaning', 'Когда не хватает смысла', 'Когда не хватает смысла', 3),
  ('reaction', 'reaction', 'Когда быстро реагируем', 'Когда быстро реагируем', 4),
  ('memory', 'memory', 'Когда запоминаем и вспоминаем', 'Когда запоминаем и вспоминаем', 1)
insert into public.cb_subgroups (id, slug, section_id, title, description, sort_order, color_token)
values
  ('info_primed', 'info_primed', 'information', 'Замечаем то, что уже есть в памяти', 'Мы охотнее обращаем внимание на вещи, которые недавно видели, которые часто повторяются или уже загружены в нашу память.', 1, 'soft-blue'),
  ('info_bizarre', 'info_bizarre', 'information', 'Странное и смешное выделяется', 'Необычные, забавные, визуально яркие или антропоморфные вещи привлекают больше внимания, чем обыденные.', 2, 'soft-blue'),
  ('info_changed', 'info_changed', 'information', 'Замечаем, когда что-то изменилось', 'Мы склонны оценивать вещи не сами по себе, а по тому, как они изменились по сравнению с предыдущим состоянием или контекстом.', 3, 'soft-blue'),
  ('info_confirmation', 'info_confirmation', 'information', 'Фокус на подтверждении своих убеждений', 'Нас привлекают детали, которые подтверждают наши существующие взгляды, и мы игнорируем то, что им противоречит.', 4, 'soft-blue'),
  ('info_flaws', 'info_flaws', 'information', 'Чужие изъяны заметнее своих', 'Мы замечаем недостатки и логические ошибки в поведении и мышлении других людей гораздо легче, чем в собственных.', 5, 'soft-blue'),
  ('meaning_patterns', 'meaning_patterns', 'meaning', 'Находим закономерности в шуме', 'Мы склонны видеть истории, паттерны и связи даже там, где данные случайны или их недостаточно.', 1, 'soft-red'),
  ('meaning_stereotypes', 'meaning_stereotypes', 'meaning', 'Заполняем пробелы стереотипами', 'Когда информации не хватает, мы достраиваем картину, используя обобщения, стереотипы и прошлый опыт.', 2, 'soft-red'),
  ('meaning_familiar', 'meaning_familiar', 'meaning', 'Считаем знакомое лучшим', 'Мы воображаем вещи и людей, с которыми мы знакомы или к которым привязаны, как более привлекательные и правильные.', 3, 'soft-red'),
  ('meaning_simplify', 'meaning_simplify', 'meaning', 'Упрощаем числа и вероятности', 'Сложная математика и статистика плохо воспринимаются мозгом, поэтому мы упрощаем вероятности, чтобы о них было легче думать.', 4, 'soft-red'),
  ('meaning_mind_reading', 'meaning_mind_reading', 'meaning', 'Иллюзия чтения мыслей', 'Мы уверены, что знаем, о чем думают другие люди, проецируя на них свои собственные мотивы и знания.', 5, 'soft-red'),
  ('meaning_projection', 'meaning_projection', 'meaning', 'Проекция на прошлое и будущее', 'Мы проецируем наш текущий настрой, эмоции и предположения на воспоминания о прошлом и прогнозы на будущее.', 6, 'soft-red'),
  ('reaction_confident', 'reaction_confident', 'reaction', 'Потребность в уверенности', 'Чтобы действовать, нам нужно быть уверенными в своей способности влиять на ситуацию и чувствовать важность своих поступков.', 1, 'soft-green'),
  ('reaction_immediate', 'reaction_immediate', 'reaction', 'Фокус на немедленном', 'Чтобы не терять концентрацию, мы отдаем предпочтение тому, что находится прямо перед нами, игнорируя отложенные последствия.', 2, 'soft-green'),
  ('reaction_completion', 'reaction_completion', 'reaction', 'Стремление к завершению', 'Мы склонны доводить до конца дела, в которые уже инвестировали время, энергию или деньги, даже если это нерационально.', 3, 'soft-green'),
  ('reaction_preserve', 'reaction_preserve', 'reaction', 'Сохранение статуса и избегание риска', 'Чтобы избежать ошибок, мы стремимся сохранить автономию, статус-кво и избегаем необратимых решений.', 4, 'soft-green'),
  ('reaction_simple', 'reaction_simple', 'reaction', 'Предпочтение простого', 'Мы предпочитаем простые на вид варианты с полной информацией, избегая сложных и двусмысленных альтернатив.', 5, 'soft-green'),
  ('memory_edit', 'memory_edit', 'memory', 'Редактирование воспоминаний', 'Мы постфактум редактируем, искажаем и усиливаем некоторые воспоминания под влиянием новой информации.', 1, 'soft-yellow'),
  ('memory_discard', 'memory_discard', 'memory', 'Отбрасывание частностей', 'Мы забываем специфические детали, чтобы формировать общие концепции и правила.', 2, 'soft-yellow'),
  ('memory_reduce', 'memory_reduce', 'memory', 'Сведение к ключевым элементам', 'События и списки сокращаются в памяти до их самых ярких элементов, начал и концовок.', 3, 'soft-yellow'),
  ('memory_store', 'memory_store', 'memory', 'Зависимость от контекста опыта', 'То, как мы сохраняем воспоминания, напрямую зависит от того, как именно и в каком контексте мы получили этот опыт.', 4, 'soft-yellow')
insert into public.cb_lessons (id, slug, section_id, subgroup_id, sort_order, title, title_en, short_text, full_text, ai_context, ai_suggestions_json, image_url, atlas_node_id, related_slugs, source_book_ref, source_atlas_ref, category, published_at, aliases_ru, aliases_en, mechanism, why_it_matters, everyday_examples_json, work_examples_json, signals_json, antidotes_json, self_check_questions_json, difficulty, atlas_blurb, image_prompt, source_refs_json, confidence)
values
  ('availability-heuristic', 'availability-heuristic', 'information', 'info_primed', 1, 'Эвристика доступности', 'Availability Heuristic', 'Мы переоцениваем вероятность событий, примеры которых легче и быстрее всего приходят нам на ум.', 'Эвристика доступности — это ментальный ярлык, при котором мы судим о частоте, вероятности или важности события по тому, насколько легко примеры всплывают в памяти. Наш мозг считает: раз я могу это быстро вспомнить, значит, это важно и случается часто.
