  ('subgroup-reaction_completion', 'reaction_completion', 'Стремление к завершению', 'Когда быстро реагируем', -212.132, 212.132, 1.1, 'soft-green', null, 'Мы склонны доводить до конца дела, в которые уже инвестировали время, энергию или деньги, даже если это нерационально.', 'subgroup', 'reaction', 'reaction_completion'),
  ('subgroup-reaction_preserve', 'reaction_preserve', 'Сохранение статуса и избегание риска', 'Когда быстро реагируем', -251.6012, 163.3917, 1.1, 'soft-green', null, 'Чтобы избежать ошибок, мы стремимся сохранить автономию, статус-кво и избегаем необратимых решений.', 'subgroup', 'reaction', 'reaction_preserve'),
  ('subgroup-reaction_simple', 'reaction_simple', 'Предпочтение простого', 'Когда быстро реагируем', -280.0741, 107.5104, 1.1, 'soft-green', null, 'Мы предпочитаем простые на вид варианты с полной информацией, избегая сложных и двусмысленных альтернатив.', 'subgroup', 'reaction', 'reaction_simple'),
  ('subgroup-memory_edit', 'memory_edit', 'Редактирование воспоминаний', 'Когда запоминаем и вспоминаем', -280.0741, -107.5104, 1.1, 'soft-yellow', null, 'Мы постфактум редактируем, искажаем и усиливаем некоторые воспоминания под влиянием новой информации.', 'subgroup', 'memory', 'memory_edit'),
  ('subgroup-memory_discard', 'memory_discard', 'Отбрасывание частностей', 'Когда запоминаем и вспоминаем', -251.6012, -163.3917, 1.1, 'soft-yellow', null, 'Мы забываем специфические детали, чтобы формировать общие концепции и правила.', 'subgroup', 'memory', 'memory_discard'),
  ('subgroup-memory_reduce', 'memory_reduce', 'Сведение к ключевым элементам', 'Когда запоминаем и вспоминаем', -212.132, -212.132, 1.1, 'soft-yellow', null, 'События и списки сокращаются в памяти до их самых ярких элементов, начал и концовок.', 'subgroup', 'memory', 'memory_reduce'),
  ('subgroup-memory_store', 'memory_store', 'Зависимость от контекста опыта', 'Когда запоминаем и вспоминаем', -163.3917, -251.6012, 1.1, 'soft-yellow', null, 'То, как мы сохраняем воспоминания, напрямую зависит от того, как именно и в каком контексте мы получили этот опыт.', 'subgroup', 'memory', 'memory_store'),
  ('node-availability-heuristic', 'availability-heuristic', 'Эвристика доступности', 'Когда много информации', 67.2668, -424.706, 0.92, 'soft-blue', 'availability-heuristic', 'Оцениваем вероятность события по тому, насколько легко его вспомнить.', 'bias', 'information', 'info_primed'),
  ('node-attentional-bias', 'attentional-bias', 'Искажение внимания', 'Когда много информации', 102.1278, -442.364, 0.96, 'soft-blue', 'attentional-bias', 'То, о чем мы думаем, определяет то, что мы замечаем в мире.', 'bias', 'information', 'info_primed'),
  ('node-illusory-truth-effect', 'illusory-truth-effect', 'Эффект иллюзии правды', 'Когда много информации', 139.7537, -457.1137, 1, 'soft-blue', 'illusory-truth-effect', 'Многократное повторение заставляет ложь казаться правдой.', 'bias', 'information', 'info_primed'),
  ('node-mere-exposure-effect', 'mere-exposure-effect', 'Эффект знакомства с объектом', 'Когда много информации', 154.0982, -401.4396, 1.04, 'soft-blue', 'mere-exposure-effect', 'То, что мы видим часто, начинает нравиться нам больше.', 'bias', 'information', 'info_primed'),
  ('node-context-effect', 'context-effect', 'Эффект контекста', 'Когда много информации', 191.8687, -411.4637, 0.92, 'soft-blue', 'context-effect', 'Окружающая среда невидимо управляет тем, как мы оцениваем вещи.', 'bias', 'information', 'info_primed'),
  ('node-cue-dependent-forgetting', 'cue-dependent-forgetting', 'Зависимое от подсказок забывание', 'Когда много информации', 231.739, -418.0682, 0.96, 'soft-blue', 'cue-dependent-forgetting', 'Мы забываем не саму информацию, а путь к ней.', 'bias', 'information', 'info_primed'),
  ('node-mood-congruence', 'mood-congruence', 'Конгруэнтность настроения', 'Когда много информации', 234.1948, -360.6283, 1, 'soft-blue', 'mood-congruence', 'Наше настроение работает как фильтр, пропускающий только похожие на него воспоминания.', 'bias', 'information', 'info_primed'),
  ('node-frequency-illusion', 'frequency-illusion', 'Иллюзия частотности', 'Когда много информации', 273.224, -362.5805, 1.04, 'soft-blue', 'frequency-illusion', 'Узнав что-то новое, вы начинаете видеть это везде.', 'bias', 'information', 'info_primed'),
  ('node-empathy-gap', 'empathy-gap', 'Разрыв эмпатии', 'Когда много информации', 313.5962, -360.7512, 0.92, 'soft-blue', 'empathy-gap', 'Сытый голодного не разумеет: мы слепы к чужим и своим эмоциям.', 'bias', 'information', 'info_primed'),
  ('node-omission-bias', 'omission-bias', 'Искажение бездействия', 'Когда много информации', 304.0559, -304.0559, 0.96, 'soft-blue', 'omission-bias', 'Мы предпочитаем бездействовать, даже если это приносит больше вреда.', 'bias', 'information', 'info_primed'),
  ('node-base-rate-fallacy', 'base-rate-fallacy', 'Ошибочное игнорирование базовой доли', 'Когда много информации', 342.6381, -297.8508, 1, 'soft-blue', 'base-rate-fallacy', 'Частные истории вытесняют из нашей головы глобальную статистику.', 'bias', 'information', 'info_primed'),
  ('node-bizarreness-effect', 'bizarreness-effect', 'Эффект причудливости', 'Когда много информации', 154.0982, -401.4396, 0.92, 'soft-blue', 'bizarreness-effect', 'Наш мозг настроен на захват аномалий и игнорирование нормы.', 'bias', 'information', 'info_bizarre'),
  ('node-humor-effect', 'humor-effect', 'Эффект юмора', 'Когда много информации', 191.8687, -411.4637, 0.96, 'soft-blue', 'humor-effect', 'Смешное запоминается лучше, потому что вызывает всплеск дофамина.', 'bias', 'information', 'info_bizarre'),
  ('node-von-restorff-effect', 'von-restorff-effect', 'Эффект фон Ресторфф', 'Когда много информации', 231.739, -418.0682, 1, 'soft-blue', 'von-restorff-effect', 'То, что нарушает шаблон, врезается в память.', 'bias', 'information', 'info_bizarre'),
  ('node-picture-superiority-effect', 'picture-superiority-effect', 'Эффект превосходства картинки', 'Когда много информации', 234.1948, -360.6283, 1.04, 'soft-blue', 'picture-superiority-effect', 'Мозг обрабатывает изображения быстрее и запоминает их надолго.', 'bias', 'information', 'info_bizarre'),
  ('node-self-reference-effect', 'self-reference-effect', 'Эффект самореференции', 'Когда много информации', 273.224, -362.5805, 0.92, 'soft-blue', 'self-reference-effect', 'Все, что связано с нами лично, врезается в память моментально.', 'bias', 'information', 'info_bizarre'),
  ('node-negativity-bias', 'negativity-bias', 'Искажение негатива', 'Когда много информации', 313.5962, -360.7512, 0.96, 'soft-blue', 'negativity-bias', 'Плохое прилипает как липучка, а хорошее скатывается как с тефлона.', 'bias', 'information', 'info_bizarre'),
  ('node-anchoring-bias', 'anchoring-bias', 'Эффект привязки', 'Когда много информации', 234.1948, -360.6283, 0.92, 'soft-blue', 'anchoring-bias', 'Первая названная цифра становится гравитационным центром для всех решений.', 'bias', 'information', 'info_changed'),
  ('node-conservatism-bias', 'conservatism-bias', 'Консерватизм (пересмотр убеждений)', 'Когда много информации', 273.224, -362.5805, 0.96, 'soft-blue', 'conservatism-bias', 'Мы держимся за старые убеждения, даже когда новые факты кричат об обратном.', 'bias', 'information', 'info_changed'),
  ('node-contrast-effect', 'contrast-effect', 'Эффект контраста', 'Когда много информации', 313.5962, -360.7512, 1, 'soft-blue', 'contrast-effect', 'Все познается в сравнении — и в этом наша слабость.', 'bias', 'information', 'info_changed'),
